+pub(crate) const FEATURE_DONE_PROMPT: &str = "work-leaf: Is this feature done? yes/no";
+pub(crate) const FEATURE_MARKED_DONE: &str = "work-leaf: feature marked done";
+pub(crate) const FEATURE_REOPENED: &str = "work-leaf: feature reopened";
+
+pub(crate) fn feature_completion_closed(lines: &[String]) -> bool {
+    latest_feature_completion_state(lines).is_some_and(|line| line == FEATURE_MARKED_DONE)
+}
+
+fn latest_feature_completion_state(lines: &[String]) -> Option<&str> {
+    lines.iter().rev().map(String::as_str).find(|line| {
+        matches!(
+            *line,
+            FEATURE_DONE_PROMPT | FEATURE_MARKED_DONE | FEATURE_REOPENED
+        )
+    })
+}
