            self.mode = UiMode::Insert;
            Vec::new()
        }
        UiKey::Char(':') if self.mode == UiMode::Command => {
            self.mode = UiMode::Prompt;
            Vec::new()
        }
        UiKey::Char(',') if self.mode == UiMode::Command => {
