        items.push(item);
        if !agent.modified_files.is_empty() {
            items.push(ListItem::new(Spans::from(vec![Span::raw(format!(
                "    files: {}",
                agent
                    .modified_files
                    .iter()
                    .map(|path| path.display().to_string())
